   626	    throw new Error(`Workflow is in sequential mode. Release the active lease before claiming another lane for ${ticket.id}.`)
   627	  }
   628	  if (!ticket.parallel_safe && workflow.parallel_mode === "parallel-lanes" && otherLeases.length > 0) {
