   630	  }
   631	  if (ticket.overlap_risk === "high" && writeLock && otherLeases.length > 0) {
   632	    throw new Error(`Ticket ${ticket.id} cannot take a write lease with overlap_risk=high while other leases are active.`)
   633	  }
   634	  const conflict = findConflictingLease(workflow, ticket)
   635	  if (conflict) throw new Error(`Lane ${ticket.lane} already has an active write lease owned by ${conflict.owner_agent}.`)
