   637	  if (existingLease && existingLease.owner_agent !== ownerAgent.trim()) {
   638	    throw new Error(`Ticket ${ticket.id} already has an active lease owned by ${existingLease.owner_agent}. Release it before changing owners.`)
   639	  }
   640	  workflow.lane_leases = workflow.lane_leases.filter((lease) => lease.ticket_id !== ticket.id)
   641	  const lease: LaneLease = { ticket_id: ticket.id, lane: ticket.lane, owner_agent: ownerAgent.trim(), write_lock: writeLock, claimed_at: new Date().toISOString(), allowed_paths: allowedPaths.map(normalizeRepoPath) }
