   275	        }
   276	
   277	        if (requested.stage === "review") {
   278	          const implementationBlocker = await validateImplementationArtifactEvidence(ticket)
   279	          if (implementationBlocker) throw new Error(implementationBlocker)
   280	        }
   281	
   282	        if (requested.stage === "qa" && !hasReviewArtifact(ticket)) {
   283	          throw new Error("Cannot move to qa before at least one review artifact exists.")
   284	        }
   285	
   286	        if (requested.stage === "smoke-test") {
   287	          const qaBlocker = await validateQaArtifactEvidence(ticket)
   288	          if (qaBlocker) throw new Error(qaBlocker)
   289	          await ensureBootstrapReadyForValidation()
   290	        }
   291	
   292	        if (requested.stage === "closeout") {
   293	          const smokeTestBlocker = await validateSmokeTestArtifactEvidence(ticket)
   294	          if (smokeTestBlocker) throw new Error(smokeTestBlocker)
   295	          await ensureBootstrapReadyForValidation()
   296	        }
   297	
   298	        if (getTicketWorkflowState(workflow, ticket.id).needs_reverification && requested.status === "done" && ticket.resolution_state !== "reopened") {
   299	          throw new Error(`Ticket ${ticket.id} still needs reverification and cannot be closed from a non-reopened state.`)
   300	        }
   301	      }
   302	
   303	      if (input.tool === "handoff_publish") {
   304	        const manifest = await loadManifest()
   305	        await ensureTargetTicketWriteLease(workflow.active_ticket)
   306	        await ensureBootstrapReadyForValidation()
   307	        const activeTicket = getTicket(manifest, workflow.active_ticket)
   308	        if (activeTicket.resolution_state === "reopened") {
   309	          throw new Error(`Cannot publish handoff while the foreground ticket ${activeTicket.id} is reopened.`)
   310	        }
   311	        const invalidatedDoneTickets = manifest.tickets.filter((ticket) => ticket.status === "done" && ticket.verification_state === "invalidated")
   312	        if (invalidatedDoneTickets.length > 0) {
   313	          throw new Error(`Cannot publish handoff while done tickets remain invalidated: ${invalidatedDoneTickets.map((ticket) => ticket.id).join(", ")}.`)
   314	        }
   315	        const pendingReverification = manifest.tickets.filter((ticket) => getTicketWorkflowState(workflow, ticket.id).needs_reverification)
   316	        if (pendingReverification.length > 0) {
   317	          throw new Error(`Cannot publish handoff while reverification is pending for: ${pendingReverification.map((ticket) => ticket.id).join(", ")}.`)
   318	        }
   319	      }
   320	    },
   321	  }
   322	}
